set -euo pipefail

FSTAB="/etc/fstab"
MOUNT_POINT="/dev/shm"
OPTION="nodev"

# Determine if /dev/shm is already configured in /etc/fstab
if grep -qE "^\s*[^#][^[:space:]]+\s+${MOUNT_POINT}\s+" "$FSTAB"; then
    # /dev/shm entry exists, ensure nodev option is present
    LINE=$(grep -E "^\s*[^#][^[:space:]]+\s+${MOUNT_POINT}\s+" "$FSTAB")

    if echo "$LINE" | awk '{print $4}' | grep -qw "$OPTION"; then
        : # nodev already present
    else
        # Add nodev to the options field (4th column)
        NEW_LINE=$(echo "$LINE" | awk -v opt="$OPTION" '{
            split($0, fields, /[[:space:]]+/)
            n = 0
            line = ""
            for (i=1; i<=NF; i++) {
                if (i == 4) {
                    if ($4 == "defaults") {
                        $4 = "defaults," opt
                    } else {
                        $4 = $4 "," opt
                    }
                }
            }
            print $0
        }')

        # Use a safer approach with a temporary file
        TMP_FSTAB=$(mktemp)
        awk -v mp="$MOUNT_POINT" -v opt="$OPTION" '
        {
            if ($0 ~ "^[[:space:]]*[^#][^[:space:]]+[[:space:]]+" mp "[[:space:]]+") {
                n = split($0, fields, /[[:space:]]+/)
                # Rebuild line preserving whitespace structure is complex; use simple split by whitespace
                split($0, cols)
                opts = cols[4]
                if (opts !~ "(^|,)" opt "(,|$)") {
                    if (opts == "defaults") {
                        cols[4] = "defaults," opt
                    } else {
                        cols[4] = opts "," opt
                    }
                }
                line = cols[1]
                for (i=2; i<=6 && i<=length(cols); i++) {
                    line = line "\t" cols[i]
                }
                print line
            } else {
                print $0
            }
        }
        ' "$FSTAB" > "$TMP_FSTAB"

        cat "$TMP_FSTAB" > "$FSTAB"
        rm -f "$TMP_FSTAB"
    fi
else
    # No explicit /dev/shm entry; add one with proper options
    echo -e "tmpfs\t${MOUNT_POINT}\ttmpfs\tdefaults,nodev,nosuid,noexec\t0\t0" >> "$FSTAB"
fi

# Apply immediately: remount /dev/shm with nodev option
if mount | grep -qE "on ${MOUNT_POINT} "; then
    mount -o remount,nodev "$MOUNT_POINT"
else
    mount "$MOUNT_POINT"
fi

exit 0

